#!/usr/bin/env node
/**
 * Generate gamification migrations (043-056) with UUID for user-ref columns.
 * Use when Neon has users.id as UUID (e.g. Neon Auth).
 *
 * Usage: node scripts/generate-neon-uuid-bundle.js [--output path]
 * With no --output, writes to stdout.
 */

const fs = require("fs");
const path = require("path");

const ROOT = path.join(__dirname, "..");
const MIGRATIONS = [
  "043_cleaner_level_system.sql",
  "044_meaningful_login_and_attribution.sql",
  "045_gamification_expansion.sql",
  "046_safety_reports.sql",
  "047_gamification_event_ingestion.sql",
  "048_gamification_reward_grants_and_choices.sql",
  "049_gamification_sql_helpers.sql",
  "050_gamification_reward_idempotency_and_effects.sql",
  "051_gamification_admin_control_plane.sql",
  "052_gamification_cash_budget_enforcement.sql",
  "053_gamification_badges.sql",
  "054_gamification_seasonal_challenges.sql",
  "055_gamification_ops_views.sql",
  "056_marketplace_health_governor.sql",
];

const USER_REF_COLUMNS = [
  "cleaner_id",
  "created_by",
  "updated_by",
  "actor_admin_user_id",
];

function toUuid(content) {
  let out = content;
  const cols = ["cleaner_id", "created_by", "updated_by", "actor_admin_user_id"];
  for (const col of cols) {
    const re = new RegExp(
      `(\\b${col}\\s+)TEXT(\\s+(?:NOT\\s+NULL|NULL)?\\s*(?:UNIQUE)?\\s*REFERENCES\\s+users\\s*\\(\\s*id\\s*[^;]+)`,
      "gi"
    );
    out = out.replace(re, "$1UUID$2");
  }
  out = out.replace(/\bBEGIN\s*;\s*\n?/g, "");
  out = out.replace(/\n?\s*COMMIT\s*;\s*\n?/g, "\n");
  return out;
}

function main() {
  const outArg = process.argv.indexOf("--output");
  const outPath = outArg >= 0 ? process.argv[outArg + 1] : null;

  const header = `-- Neon UUID Bundle: Gamification 043-056
-- For databases where users.id is UUID (e.g. Neon Auth).
-- Run after base schema. Do NOT use with canonical schema (users.id TEXT).
-- Generated by scripts/generate-neon-uuid-bundle.js

`;

  let buf = header;
  for (const m of MIGRATIONS) {
    const full = path.join(ROOT, "DB", "migrations", m);
    if (!fs.existsSync(full)) {
      console.error(`Skip (not found): ${m}`);
      continue;
    }
    buf += `\n-- === ${m} ===\n`;
    buf += toUuid(fs.readFileSync(full, "utf8"));
    buf += "\n";
  }

  if (outPath) {
    const dir = path.dirname(outPath);
    if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
    fs.writeFileSync(path.resolve(outPath), buf);
    console.log(`Wrote ${path.resolve(outPath)}`);
  } else {
    process.stdout.write(buf);
  }
}

main();
